private void OnNextLevelClicked()
{
    HideVictory();
    int nextIndex = GameManager.Instance.CurrentLevelData != null ? 1 : 0;
    var levels = GameManager.Instance.Levels;
    if (levels != null && nextIndex < levels.Length)
        GameManager.Instance.LoadLevel(nextIndex);  // <-- reloads within same scene
    else
        SceneManager.LoadScene(SceneManager.GetActiveScene().name); // fallback: reload scene
}
```
> ⚠️ **Note:** The `nextIndex` calculation is **hardcoded to 1** (when `CurrentLevelData` is not null), not dynamically computed from the current level index. This means it always attempts level index 1 regardless of which level was completed. This is likely a **bug** or placeholder logic.

**Restart button** (line 121): calls `GameManager.Instance.RestartGame()` which reloads the scene.

**Main menu button** (lines 124-134):
